Object.assign(controls, {
  textPreset: 'QUAESTOR',
  circleCount: 120,
  circleSize: 60,
  spread: 20,
  hoverRadius: 150,
  pushForce: 80,
  fontSize: 20,
  outlineWeight: 2,
  wobbleIntensity: 4,
  attractMode: false
});

const sketch = (p) => {
  let circles = [];
  let lastCircleCount = -1;
  let lastTextPreset = '';
  let lastSpread = -1;

  class Circle {
    constructor(bx, by, ch) {
      this.bx = bx;
      this.by = by;
      this.x  = bx;
      this.y  = by;
      this.ch = ch;
      this.vx = 0;
      this.vy = 0;
      this.scale = 1;
      this.sat   = 0;
      this.hue   = p.random(0, 360);
      this.phase = p.random(0, 360);
      this.nox   = p.random(0, 1000);
      this.noy   = p.random(2000, 3000);
    }

    update(t) {
      const wobble = controls.wobbleIntensity;
      const wx = (p.noise(this.nox + t) - 0.5) * 2 * wobble;
      const wy = (p.noise(this.noy + t) - 0.5) * 2 * wobble;

      let tx = this.bx + wx;
      let ty = this.by + wy;

      const dx   = this.bx - p.mouseX;
      const dy   = this.by - p.mouseY;
      const dist = p.sqrt(dx * dx + dy * dy);
      const hr   = controls.hoverRadius;
      const attract = controls.attractMode;

      let tScale = 1;
      let tSat   = 0;
      let tHue   = this.hue;

      if (dist < hr && dist > 0.01) {
        const norm = dist / hr;
        if (norm < 0.5) {
          const f = 1 - norm / 0.5;
          tScale = 1 + f * 0.75;
          tSat   = 70 + f * 30;
          tHue   = (this.phase + p.frameCount * 2.2) % 360;
        } else {
          const f   = (1 - norm) / 0.5;
          const ang = p.atan2(dy, dx);
          const dir = attract ? -1 : 1;
          tx += p.cos(ang) * f * controls.pushForce * dir;
          ty += p.sin(ang) * f * controls.pushForce * dir;
          tSat = f * 48;
          tHue = (this.phase + p.frameCount * 1.1) % 360;
        }
      }

      this.scale += (tScale - this.scale) * 0.14;
      this.sat   += (tSat   - this.sat)   * 0.1;

      let dHue = tHue - this.hue;
      if (dHue >  180) dHue -= 360;
      if (dHue < -180) dHue += 360;
      this.hue = ((this.hue + dHue * 0.07) + 360) % 360;

      this.vx = (this.vx + (tx - this.x) * 0.14) * 0.72;
      this.vy = (this.vy + (ty - this.y) * 0.14) * 0.72;
      this.x += this.vx;
      this.y += this.vy;
    }

    draw() {
      const sz = controls.circleSize * this.scale;
      p.push();
      p.translate(this.x, this.y);

      p.colorMode(p.HSB, 360, 100, 100);
      p.fill(this.hue, this.sat, 100);
      p.strokeWeight(controls.outlineWeight);
      p.stroke(0, 0, 0);
      p.circle(0, 0, sz);

      p.colorMode(p.RGB, 255);
      p.fill(0);
      p.noStroke();
      p.textAlign(p.CENTER, p.CENTER);
      p.textStyle(p.BOLD);
      p.textSize(controls.fontSize);
      p.text(this.ch, 0, 1);

      p.pop();
    }
  }

  function buildGrid() {
    circles = [];
    const str    = controls.textPreset || 'QUAESTOR';
    const count  = Math.min(Math.floor(controls.circleCount), 200);
    const spread = controls.spread;
    const aspect = p.width / p.height;
    const cols   = Math.ceil(Math.sqrt(count * aspect));
    const rows   = Math.ceil(count / cols);
    const cw     = p.width  / cols;
    const ch     = p.height / rows;

    let ci = 0, n = 0;
    for (let r = 0; r < rows && n < count; r++) {
      for (let c = 0; c < cols && n < count; c++) {
        const bx = cw * (c + 0.5) + p.random(-spread, spread);
        const by = ch * (r + 0.5) + p.random(-spread, spread);
        circles.push(new Circle(bx, by, str[ci % str.length]));
        ci++; n++;
      }
    }

    lastCircleCount = Math.min(Math.floor(controls.circleCount), 200);
    lastTextPreset  = controls.textPreset;
    lastSpread      = controls.spread;
  }

  p.setup = () => {
    p.createCanvas(p.windowWidth, p.windowHeight);
    buildGrid();
  };

  p.draw = () => {
    const currentCount  = Math.min(Math.floor(controls.circleCount), 200);
    const currentPreset = controls.textPreset;
    const currentSpread = controls.spread;
    if (
      currentCount  !== lastCircleCount ||
      currentPreset !== lastTextPreset  ||
      currentSpread !== lastSpread
    ) {
      buildGrid();
    }

    p.colorMode(p.RGB);
    p.background(18);
    const t = p.millis() * 0.0005;
    for (const c of circles) {
      c.update(t);
      c.draw();
    }
  };

  p.mousePressed = () => buildGrid();

  p.windowResized = () => {
    p.resizeCanvas(p.windowWidth, p.windowHeight);
    buildGrid();
  };
};

new p5(sketch);
